import React from 'react';

const Card = ({ title, value, icon, color, children }) => {
  return (
    <div className="card" style={{ padding: '20px', borderRadius: '12px', boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)', borderLeft: `4px solid ${color || 'transparent'}` }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <div>
          <div className="kpi-muted" style={{ fontSize: '14px', color: '#6b7280', marginBottom: '4px' }}>{title}</div>
          <div className="kpi" style={{ fontSize: '24px', fontWeight: 'bold', color: '#1f2937' }}>{value}</div>
        </div>
        {icon && <div style={{ fontSize: '24px', padding: '12px', borderRadius: '50%', background: `${color}20`, color: color }}>{icon}</div>}
        <div>{children}</div>
      </div>
    </div>
  );
}
export default Card;
